mapper.select:
SELECT CAST(SUBSTRING(voucher_no, 8) AS UNSIGNED) AS max_no
FROM gl_voucher
WHERE company_id = #{companyId}
AND accounting_year = #{accountingYear}
AND accounting_period = #{accountingPeriod}
AND is_deleted = 0
ORDER BY voucher_no DESC
LIMIT 1

SELECT * FROM gl_voucher

    is_deleted = 0

        AND company_id = #{companyId}


        AND accounting_year = #{accountingYear}


        AND accounting_period = #{accountingPeriod}


        AND status = #{status}


        AND voucher_no LIKE CONCAT('%', #{voucherNo}, '%')


        AND voucher_date >= #{startDate}


        AND voucher_date <= #{endDate}


ORDER BY voucher_date DESC, voucher_no DESC

SELECT COUNT(*) FROM gl_voucher

    is_deleted = 0

        AND company_id = #{companyId}


        AND accounting_year = #{accountingYear}


        AND accounting_period = #{accountingPeriod}


        AND status = #{status}

mapper.update:
UPDATE gl_voucher SET status = #{status}
WHERE id = #{id}
AND is_deleted = 0
